### Multer Middleware

Multer is a middleware for handling multipart/form-data (file uploads).

```bash
npm install multer
```

### Single File Upload

```javascript
const multer = require('multer');
const upload = multer({ dest: 'uploads/' });

app.post('/upload', upload.single('avatar'), (req, res) => {
  console.log(req.file);  // File info
  console.log(req.body);  // Other form fields
  res.json({ file: req.file });
});
```

### Multiple File Upload

```javascript
// Multiple files, same field name
app.post('/upload', upload.array('photos', 5), (req, res) => {
  console.log(req.files); // Array of files
});

// Multiple files, different field names
app.post('/upload', upload.fields([
  { name: 'avatar', maxCount: 1 },
  { name: 'gallery', maxCount: 8 }
]), (req, res) => {
  console.log(req.files.avatar);
  console.log(req.files.gallery);
});
```

### File Filtering

Filter by file type:

```javascript
const fileFilter = (req, file, cb) => {
  if (file.mimetype.startsWith('image')) {
    cb(null, true);
  } else {
    cb(new Error('Only images allowed'), false);
  }
};

const upload = multer({ fileFilter });
```

### Storage Configuration

Disk storage with custom filename:

```javascript
const storage = multer.diskStorage({
  destination: (req, file, cb) => cb(null, 'uploads/'),
  filename: (req, file, cb) => {
    const unique = Date.now() + '-' + file.originalname;
    cb(null, unique);
  }
});

const upload = multer({ storage });
```

### File Validation

```javascript
const upload = multer({
  storage,
  limits: { fileSize: 5 * 1024 * 1024 }, // 5MB
  fileFilter
});
```

codeExample:
const multer = require('multer');
const path = require('path');

const storage = multer.diskStorage({
  destination: './uploads/',
  filename: (req, file, cb) => {
    cb(null, Date.now() + path.extname(file.originalname));
  }
});

const upload = multer({
  storage,
  limits: { fileSize: 2 * 1024 * 1024 },
  fileFilter: (req, file, cb) => {
    const allowed = /jpeg|jpg|png|gif/;
    const extOk = allowed.test(path.extname(file.originalname).toLowerCase());
    cb(null, extOk);
  }
});

app.post('/api/upload', upload.single('image'), (req, res) => {
  res.json({ filename: req.file.filename, path: req.file.path });
});
